#include <stdio.h>
#include <math.h>

// Function to calculate the prefix sum for a given n
double calculatePrefixSum(int n) {
    double sum = 0.0;
    for (int i = 2; i <= n + 1; i++) {
        sum += pow(i, 2) / i;
    }
    return sum;
}

int main(void) {
    int n;
    printf("Enter an integer n: ");
    scanf("%d", &n);

    // Array to store prefix sums
    double prefixSums[n];

    // Calculate and store each prefix sum in the array
    for (int i = 0; i < n; i++) {
        prefixSums[i] = calculatePrefixSum(i + 2);
    }

    // Print the generated values
    printf("Generated values: ");
    for (int i = 0; i < n; i++) {
        printf("%.6f ", prefixSums[i]);
    }
    printf("\n");

    return 0;
}

#include <stdio.h>
#include <string.h>

#define MAX_PHONE_LENGTH 15
#define DAY_BILLING_START 7 * 60 + 0 // 7:00 AM in minutes
#define DAY_BILLING_END 23 * 60 + 59 // 11:59 PM in minutes

typedef struct {
    char phone[MAX_PHONE_LENGTH];
    int start_time;
    int end_time;
} CallRecord;

int main(void) {
    CallRecord call;
    double total_day = 0.0, total_night = 0.0;
    char phone_number[MAX_PHONE_LENGTH];

    while (1) {
        scanf("%s %d:%d", call.phone, &call.start_time, &call.end_time);

        if (strcmp(call.phone, "#") == 0) {
            break;
        }

        int duration = call.end_time - call.start_time;

        if (duration < 0) {
            duration += 24 * 60; // Handle wrap-around from midnight
        }

        double fee = 0.0;
        if (call.start_time >= DAY_BILLING_START && call.end_time <= DAY_BILLING_END) {
            fee = duration * 0.15; // Day rate
        } else {
            fee = duration * 0.25; // Night rate
        }

        printf("%s, %.2f\n", call.phone, fee);

        total_day += (call.start_time >= DAY_BILLING_START && call.end_time <= DAY_BILLING_END) ? fee : 0;
        total_night += (call.start_time < DAY_BILLING_START || call.end_time > DAY_BILLING_END) ? fee : 0;
    }

    printf("Total day: %.2f\n", total_day);
    printf("Total night: %.2f\n", total_night);

    return 0;
}

#include <stdio.h>

// Helper function to calculate the term of the series
double calculateTerm(int n) {
    return (double)n / ((double)(n + 1) * (double)(n + 1));
}

int main(void) {
    int n;

    // Read input
    printf("Enter a value for n: ");
    scanf("%d", &n);

    double result = 0.0;
    int sign = 1; // Start with positive sign

    // Calculate the alternating series
    for (int i = 1; i <= n; ++i) {
        result += sign * calculateTerm(i);
        sign *= -1; // Alternate sign
    }

    // Print the result
    printf("The result is: %.6f\n", result);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

// Function to calculate factorial of a number
unsigned long long factorial(int n) {
    unsigned long long result = 1;
    for (int i = 2; i <= n; ++i) {
        result *= i;
    }
    return result;
}

// Function to compute the weighted sum
double weightedSum(double arr[], int size) {
    double sum = 0.0;
    for (int i = 0; i < size; ++i) {
        sum += arr[i] / factorial(i + 1);
    }
    return sum;
}

// Function to print an array
void printArray(double arr[], int size) {
    printf("[");
    for (int i = 0; i < size; ++i) {
        printf("%.2f", arr[i]);
        if (i < size - 1) {
            printf(", ");
        }
    }
    printf("]\n");
}

// Main function
int main() {
    int n;
    scanf("%d", &n);

    double *arr = (double *)malloc(n * sizeof(double));
    for (int i = 0; i < n; ++i) {
        scanf("%lf", &arr[i]);
    }

    printf("Original array: ");
    printArray(arr, n);

    // Sort the array
    for (int i = 0; i < n - 1; ++i) {
        for (int j = 0; j < n - i - 1; ++j) {
            if (arr[j] > arr[j + 1]) {
                double temp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = temp;
            }
        }
    }

    printf("Sorted array: ");
    printArray(arr, n);

    double weightedSumResult = weightedSum(arr, n);
    printf("Weighted sum: %.4f\n", weightedSumResult);

    free(arr);
    return 0;
}

#include <stdio.h>

// Helper function to compute the term of the series
double computeTerm(int n) {
    return (double)n / ((n + 1) * (n + 1));
}

int main(void) {
    int n;
    double sum = 0.0;

    // Read input
    printf("Enter a value for n: ");
    scanf("%d", &n);

    // Compute the alternating series
    for (int i = 1; i <= n; ++i) {
        if (i % 2 == 0) {
            sum -= computeTerm(i);
        } else {
            sum += computeTerm(i);
        }
    }

    // Print the result
    printf("The result is: %.6f\n", sum);

    return 0;
}

