#include <stdio.h>

int main(void) {
    int n;

    // Read input value of n
    scanf("%d", &n);

    // Print upper half of the diamond
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n - i; j++) {
            printf(" ");
        }
        for (int k = 1; k <= 2 * i - 1; k++) {
            printf("%d", i);
        }
        printf("\n");
    }

    // Print lower half of the diamond
    for (int i = n - 1; i >= 1; i--) {
        for (int j = 1; j <= n - i; j++) {
            printf(" ");
        }
        for (int k = 1; k <= 2 * i - 1; k++) {
            printf("%d", i);
        }
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char word1[50], word2[50];
    int i, j;
    int count1[26] = {0}, count2[26] = {0};

    while (1) {
        printf("Enter two words: ");
        scanf("%s %s", word1, word2);

        // Count the frequency of each letter in both words
        for (i = 0; word1[i]; i++) {
            count1[word1[i] - 'a']++;
        }
        for (i = 0; word2[i]; i++) {
            count2[word2[i] - 'a']++;
        }

        // Check if the words are anagrams
        int is_anagram = 1;
        for (i = 0; i < 26; i++) {
            if (count1[i] != count2[i]) {
                is_anagram = 0;
                break;
            }
        }

        printf("Are these words anagrams? %s\n", is_anagram ? "Yes" : "No");

        // Ask the user if they want to continue
        char choice;
        printf("Do you want to continue? (Y/N): ");
        scanf(" %c", &choice);
        if (choice != 'Y' && choice != 'y') {
            break;
        }
    }

    printf("Bye\n");
    return 0;
}
